// ─── POST Handler ─────────────────────────────────────────────────────────────
export async function POST(req: NextRequest) {
  const start  = Date.now();
  const client = db();

  // Auth check
  const ingestSecret = process.env.INGESTION_SECRET;
  const reqSecret    = req.headers.get("x-ingestion-secret");
  if (ingestSecret && reqSecret !== ingestSecret) {
    return NextResponse.json({ ok: false, error: "Unauthorized" }, { status: 401 });
  }

  try {
    // Current count
    const { count: before, error: countErr } = await client
      .from("roadmap_tasks")
      .select("id", { count: "exact", head: true });
    if (countErr) throw new Error(`Count error: ${countErr.message}`);

    console.log(`[ingest-v3] Current task count: ${before ?? 0}`);

    const allTasks = TASKS_BATCH_1;
    let inserted = 0;
    let errors   = 0;
    const failedIds: string[] = [];

    // Insert in micro-batches of 100
    const MICRO_BATCH = 100;
    for (let i = 0; i < allTasks.length; i += MICRO_BATCH) {
      const batch = allTasks.slice(i, i + MICRO_BATCH);
      // Map to roadmap_tasks schema (drop extra fields)
      const rows = batch.map((t) => ({
        id         : t.id,
        roadmap_id : t.roadmap_id ?? "ECOSYSTEM_v3",
        phase_id   : t.phase_id,
        title      : t.title,
        description: t.description,
        depends_on : t.depends_on ?? [],
        status     : "pending" as const,
        source     : t.source ?? "canonical_ingestion_v3",
        updated_at : t.updated_at ?? Date.now(),
      }));

      const { error } = await client
        .from("roadmap_tasks")
        .upsert(rows, {
          onConflict: "id",
          ignoreDuplicates: true,
        });

      if (error) {
        if (error.code !== "23505") { // ignore unique violations
          console.error(`[ingest-v3] Batch error at ${i}:`, error.message);
          failedIds.push(...batch.map(t => t.id));
          errors++;
        }
      } else {
        inserted += batch.length;
      }
    }

    // Final count
    const { count: after } = await client
      .from("roadmap_tasks")
      .select("id", { count: "exact", head: true });

    const durationMs = Date.now() - start;
    console.log(`[ingest-v3] COMPLETE: ${before ?? 0} → ${after ?? 0} tasks | +${(after??0) - (before??0)} new | ${durationMs}ms`);

    return NextResponse.json({
      ok              : true,
      before          : before ?? 0,
      after           : after  ?? 0,
      inserted,
      newTasks        : (after ?? 0) - (before ?? 0),
      batchErrors     : errors,
      totalInBatch    : allTasks.length,
      totalCatalog    : 21870,
      batchesRemaining: 4,
      nextBatch       : "/api/canonical/ingest-ecosystem-v3-b2",
      durationMs,
    });

  } catch (err) {
    return NextResponse.json(
      { ok: false, error: String(err) },
      { status: 500 }
    );
  }
}

// ─── GET — status check ───────────────────────────────────────────────────────
export async function GET() {
  const { count } = await db()
    .from("roadmap_tasks")
    .select("id", { count: "exact", head: true });
  return NextResponse.json({
    ok        : true,
    current   : count ?? 0,
    target    : 21870,
    remaining : Math.max(0, 21870 - (count ?? 0)),
    endpoint  : "/api/canonical/ingest-ecosystem-v3",
    status    : (count ?? 0) >= 21870 ? "complete" : "pending",
  });
}
